# 输入获取
quacks = input()


# 算法入口
def getResult():
    q = []
    u, a, c = 0, 0, 0

    rans = []

    for i in range(len(quacks)):
        char = quacks[i]

        if char == 'q':
            q.append(i)
        elif char == 'u':
            if u + 1 <= len(q):
                u += 1
        elif char == 'a':
            if a + 1 <= u:
                a += 1
        elif char == 'c':
            if c + 1 <= a:
                c += 1
        elif char == 'k':
            if c >= 1:
                rans.append([q.pop(0), i])
                u -= 1
                a -= 1
                c -= 1
        else:
            return -1

    if len(rans) == 0:
        return -1

    ans = 1
    for i in range(len(rans)):
        count = 1
        for j in range(i + 1, len(rans)):
            if rans[i][1] >= rans[j][0]:
                count += 1

        ans = max(ans, count)

    return ans


# 算法调用
print(getResult())
